={
  "model": "qwen2.5-1.5b-instruct",
  "messages": [
    {
      "role": "system",
      "content": "You are a product description writer. You MUST describe exactly the product mentioned in the file name. Do NOT describe anything else. Start directly with the description, using keywords: 'product photography', 'studio lighting', 'highly detailed'. Example: file 'Sneakers' → 'A pair of sneakers, product photography, white background, studio lighting, highly detailed.'"
    },
    {
      "role": "user",
      "content": "Product file name: {{ $('Google Drive Trigger').first().json.name }}"
    }
  ],
  "temperature": 0.5,
  "max_tokens": 400
}

={
  "prompt": {
    "3": {
      "inputs": { "ckpt_name": "juggernautXL_ragnarok.safetensors" },
      "class_type": "CheckpointLoaderSimple"
    },
    "4": {
      "inputs": { "text": "{{ $json.prompt }}", "clip": ["3", 1] },
      "class_type": "CLIPTextEncode"
    },
    "5": {
      "inputs": { "text": "blurry, blurry text, out of focus, pixelated, distorted, ugly, low quality, jpeg artifacts, watermark, studio light, light stand, photography equipment, wrong product", "clip": ["3", 1] },
      "class_type": "CLIPTextEncode"
    },
    "6": {
      "inputs": {
        "seed": {{ $json.seed }},
        "steps": 35,
        "cfg": 4.0,
        "sampler_name": "dpmpp_2m_sde",
        "scheduler": "karras",
        "denoise": 1,
        "model": ["3", 0],
        "positive": ["4", 0],
        "negative": ["5", 0],
        "latent_image": ["7", 0]
      },
      "class_type": "KSampler"
    },
    "7": {
      "inputs": { "width": 1024, "height": 1024, "batch_size": 1 },
      "class_type": "EmptyLatentImage"
    },
    "8": {
      "inputs": { "samples": ["6", 0], "vae": ["3", 2] },
      "class_type": "VAEDecode"
    },
    "9": {
      "inputs": { "filename_prefix": "ComfyUI_Final", "images": ["8", 0] },
      "class_type": "SaveImage"
    }
  },
  "client_id": "n8n-{{ $randomInt }}"
}

parameters.jsCode:
const file = $('Google Drive Trigger').first().json;
const fileName = file.name || file.fileName || '';
const name = fileName.toLowerCase();

let prompt = "";
if (name.includes("кроссовки") || name.includes("shoes") || name.includes("sneakers")) {
  prompt = "кроссовки, белый фон, студийное освещение, 8к, высокое качество";
} else if (name.includes("сумка") || name.includes("bag")) {
  prompt = "сумка, белый фон, студийное освещение, 8к, высокое качество";
} else {
  prompt = "кроссовки, белый фон, студийное освещение, 8к";
}

return {
  prompt: prompt,
  seed: Math.floor(Math.random() * 100000000000000)
};
